<?php
$rows = $wpdb->get_results( "SELECT p.*,l.loan_number,c.first_name,c.last_name,u.display_name FROM {$wpdb->prefix}ct_payments p JOIN {$wpdb->prefix}ct_loans l ON l.id=p.loan_id JOIN {$wpdb->prefix}ct_clients c ON c.id=l.client_id LEFT JOIN {$wpdb->users} u ON u.ID=p.recorded_by ORDER BY p.created_at DESC LIMIT 50" );
?><div class="ct-titlebar"><div><h1>Payments</h1><div class="ct-muted">Immutable receipt ledger and controlled reversals.</div></div><?php if ( current_user_can( 'creditrack_record_payments' ) ) { ?><a class="ct-button" href="#payment-form">Record payment</a><?php } ?></div><div class="ct-table-wrap"><table><thead><tr><th>Receipt</th><th>Date</th><th>Borrower / loan</th><th>Method</th><th>Amount</th><th>Recorder</th><th>Status / action</th></tr></thead><tbody><?php foreach ( $rows as $row ) { ?><tr><td>CT-R-<?php echo esc_html( $row->id ); ?></td><td><?php echo esc_html( $row->payment_date ); ?></td><td><?php echo esc_html( "$row->first_name $row->last_name" ); ?><div class="ct-muted"><?php echo esc_html( $row->loan_number ); ?></div></td><td><?php echo esc_html( $row->method ); ?><div class="ct-muted"><?php echo esc_html( $row->reference_number ); ?></div></td><td><?php echo esc_html( $currency . number_format_i18n( $row->amount, 2 ) ); ?></td><td><?php echo esc_html( $row->display_name ); ?></td><td><?php if ( ! empty( $row->is_reversal ) ) { ?><span class="ct-badge">Reversal</span><?php } elseif ( ! empty( $row->reversed_at ) ) { ?><span class="ct-badge">Reversed</span><?php } elseif ( current_user_can( 'creditrack_reverse_payments' ) ) { ?><form class="ct-inline-form" method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_reverse_payment"><input type="hidden" name="payment_id" value="<?php echo esc_attr( $row->id ); ?>"><label class="screen-reader-text" for="reason-<?php echo esc_attr( $row->id ); ?>">Reversal reason</label><input id="reason-<?php echo esc_attr( $row->id ); ?>" name="reason" placeholder="Required reason" required><button class="ct-danger-button" type="submit" data-confirm="Post a compensating reversal?">Reverse</button></form><?php } else { ?><span class="ct-badge Active">Posted</span><?php } ?></td></tr><?php } if ( ! $rows ) { ?><tr><td colspan="7">No payments have been recorded.</td></tr><?php } ?></tbody></table></div>
<?php if ( current_user_can( 'creditrack_record_payments' ) ) { $loans = $wpdb->get_results( "SELECT l.id,l.loan_number,l.outstanding,c.first_name,c.last_name FROM {$wpdb->prefix}ct_loans l JOIN {$wpdb->prefix}ct_clients c ON c.id=l.client_id WHERE l.status IN ('Active','Defaulted') ORDER BY l.loan_number" ); ?><section id="payment-form" class="ct-card"><h2>Record payment</h2><form class="ct-form" method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_post_payment"><input type="hidden" name="idempotency_key" value="<?php echo esc_attr( wp_generate_uuid4() ); ?>"><div class="ct-field"><label for="loan_id">Loan</label><select id="loan_id" name="loan_id" required><option value="">Select</option><?php foreach ( $loans as $loan ) { ?><option value="<?php echo esc_attr( $loan->id ); ?>"><?php echo esc_html( "$loan->loan_number — $loan->first_name $loan->last_name — outstanding $currency$loan->outstanding" ); ?></option><?php } ?></select></div><div class="ct-field"><label for="amount">Amount</label><input id="amount" name="amount" required inputmode="decimal"></div><div class="ct-field"><label for="payment_date">Payment date</label><input id="payment_date" name="payment_date" type="date" value="<?php echo esc_attr( gmdate( 'Y-m-d' ) ); ?>" required></div><div class="ct-field"><label for="method">Method</label><select id="method" name="method"><?php foreach ( array( 'Cash','Bank Transfer','Mobile Money','Check','Other' ) as $method ) { ?><option><?php echo esc_html( $method ); ?></option><?php } ?></select></div><div class="ct-field"><label for="reference_number">Reference</label><input id="reference_number" name="reference_number"></div><div class="ct-field full"><label for="payment_notes">Notes</label><textarea id="payment_notes" name="notes"></textarea></div><div><button type="submit">Post payment</button></div></form></section><?php }
